import React, { useState, useEffect, useContext } from 'react';
import api from '../utils/api';
import { AuthContext } from '../context/AuthContext';
import { Link } from 'react-router-dom';
import './WorkerDashboardNew.css';

const WorkerDashboard = () => {
  const { user } = useContext(AuthContext);
  const [activePage, setActivePage] = useState('dashboard');
  const [activeTab, setActiveTab] = useState('available');
  const [jobs, setJobs] = useState([]);
  const [myJobs, setMyJobs] = useState([]);
  const [earnings, setEarnings] = useState(null);
  const [loading, setLoading] = useState(true);
  const [filter, setFilter] = useState('all');
  const [appliedJobs, setAppliedJobs] = useState(new Set());
  const [applyingJobId, setApplyingJobId] = useState(null);
  const [profileData, setProfileData] = useState(user || {});
  const [isEditing, setIsEditing] = useState(false);
  const [monthlyEarnings, setMonthlyEarnings] = useState({});
  const [workAnalytics, setWorkAnalytics] = useState({
    dailyHours: [],
    dailyIncome: [],
    monthlyIncome: [],
    workCapacity: []
  });
  const [analyticsFilter, setAnalyticsFilter] = useState('7days');
  const [notifications, setNotifications] = useState([]);

  const categories = [
    { id: 'all', label: 'All Jobs', icon: '📋' },
    { id: 'painting', label: 'Painting', icon: '🎨' },
    { id: 'electrical', label: 'Electrical', icon: '⚡' },
    { id: 'masonry', label: 'Masonry', icon: '🧱' },
    { id: 'plumbing', label: 'Plumbing', icon: '🚰' },
    { id: 'carpentry', label: 'Carpentry', icon: '🪚' },
    { id: 'welding', label: 'Welding', icon: '🔥' },
    { id: 'construction', label: 'Construction', icon: '🏗️' },
    { id: 'cleaning', label: 'Cleaning', icon: '🧹' },
    { id: 'gardening', label: 'Gardening', icon: '🌱' },
    { id: 'loading', label: 'Loading', icon: '📦' },
    { id: 'fabrication', label: 'Fabrication', icon: '🛠️' },
    { id: 'tiling', label: 'Tiling', icon: '📐' }
  ];

  const handleApplyJob = async (jobId) => {
    try {
      setApplyingJobId(jobId);
      const response = await api.post(`/jobs/${jobId}/apply`, {
        proposedRate: undefined,
        message: 'Interested in this job'
      });

      if (response.data.success) {
        setAppliedJobs(new Set([...appliedJobs, jobId]));
        alert('✅ Job application submitted successfully!');
      }
    } catch (error) {
      alert('❌ ' + (error.response?.data?.message || 'Failed to apply for job'));
    } finally {
      setApplyingJobId(null);
    }
  };
  
  const handleAcceptJob = async (jobId) => {
    if (!window.confirm('Are you sure you want to accept this job?')) return;
    
    try {
      const response = await api.post(`/jobs/${jobId}/accept`);
      
      if (response.data.success) {
        alert('✅ Job accepted successfully! A chat conversation has been created with the employer.');
        // Refresh dashboard data
        fetchDashboardData();
      }
    } catch (error) {
      alert('❌ ' + (error.response?.data?.message || 'Failed to accept job'));
    }
  };
  
  const handleRejectJob = async (jobId) => {
    if (!window.confirm('Are you sure you want to reject this job?')) return;
    
    try {
      const response = await api.post(`/jobs/${jobId}/reject`);
      
      if (response.data.success) {
        alert('❌ Job rejected successfully. Notification sent to employer.');
        // Refresh dashboard data
        fetchDashboardData();
      }
    } catch (error) {
      alert('❌ ' + (error.response?.data?.message || 'Failed to reject job'));
    }
  };
  const handleSaveProfile = async () => {
    try {
      const response = await api.put('/workers/profile', profileData);
      if (response.data.success) {
        alert('✅ Profile updated successfully!');
        setIsEditing(false);
      }
    } catch (error) {
      alert('❌ Error updating profile: ' + (error.response?.data?.message || 'Unknown error'));
    }
  };

  const handleProfileChange = (field, value) => {
    // Handle nested properties (e.g., 'location.city')
    if (field.includes('.')) {
      const [parent, child] = field.split('.');
      setProfileData({
        ...profileData,
        [parent]: {
          ...(profileData[parent] || {}),
          [child]: value
        }
      });
    } else {
      setProfileData({
        ...profileData,
        [field]: value
      });
    }
  };

  useEffect(() => {
    const fetchDashboardData = async () => {
      try {
        setLoading(true);
        const query = filter !== 'all' ? `?category=${filter}` : '';
        const [jobsRes, myJobsRes, earningsRes] = await Promise.all([
          api.get(`/workers/available-jobs${query}`),
          api.get('/workers/my-jobs?status=assigned'),
          api.get('/workers/earnings')
        ]);
        setJobs(jobsRes.data.jobs);
        setMyJobs(myJobsRes.data.jobs);
        setEarnings(earningsRes.data.earnings);
        setMonthlyEarnings(earningsRes.data.earnings?.monthlyBreakdown || {});
        
        // Fetch work analytics
        fetchWorkAnalytics();
      } catch (error) {
        console.error('Error fetching dashboard data:', error);
      } finally {
        setLoading(false);
      }
    };

    fetchDashboardData();
    fetchNotifications();
  }, [filter, activePage, analyticsFilter]);

  const fetchWorkAnalytics = async () => {
    try {
      const response = await api.get(`/workers/analytics?period=${analyticsFilter}`);
      if (response.data.success) {
        setWorkAnalytics(response.data.analytics);
      }
    } catch (error) {
      console.error('Error fetching analytics:', error);
      // Fallback to mock data if API fails
      const mockAnalytics = generateMockAnalytics(analyticsFilter);
      setWorkAnalytics(mockAnalytics);
    }
  };

  const fetchNotifications = async () => {
    try {
      // Get conversations that have job offers for this worker
      const response = await api.get('/chat/conversations');
      if (response.data.success) {
        const jobOfferConversations = response.data.conversations.filter(
          conv => conv.jobOffer && conv.jobOffer.status === 'pending'
        );
        
        // Transform to notification format
        const newNotifications = jobOfferConversations.map(conv => {
          const otherParticipant = conv.participants.find(p => p._id !== user.id);
          return {
            id: conv._id,
            type: 'job_offer',
            title: 'Job Offer Received',
            message: `${otherParticipant?.name} offered you a job`,
            timestamp: conv.jobOffer.offeredAt,
            status: 'unread',
            conversationId: conv._id,
            conversation: conv // Store the full conversation for later use
          };
        });
        
        setNotifications(newNotifications);
      }
    } catch (error) {
      console.error('Error fetching notifications:', error);
    }
  };
  
  const generateMockAnalytics = (filter) => {
    const days = filter === '7days' ? 7 : filter === '30days' ? 30 : 90;
    const dailyHours = [];
    const dailyIncome = [];
    const workCapacity = [];
    
    for (let i = days - 1; i >= 0; i--) {
      const date = new Date();
      date.setDate(date.getDate() - i);
      
      // Generate realistic mock data
      const hours = Math.floor(Math.random() * 10) + 4; // 4-14 hours
      const income = hours * (Math.floor(Math.random() * 300) + 200); // ₹200-500 per hour
      const capacity = Math.min(100, Math.floor(hours / 12 * 100)); // Percentage capacity
      
      dailyHours.push({
        date: date.toLocaleDateString('en-US', { month: 'short', day: 'numeric' }),
        hours: hours
      });
      
      dailyIncome.push({
        date: date.toLocaleDateString('en-US', { month: 'short', day: 'numeric' }),
        income: income
      });
      
      workCapacity.push({
        date: date.toLocaleDateString('en-US', { month: 'short', day: 'numeric' }),
        capacity: capacity
      });
    }
    
    // Calculate monthly income
    const monthlyIncome = [
      { month: 'Jan 2024', income: 45000 },
      { month: 'Feb 2024', income: 52000 },
      { month: 'Mar 2024', income: 48000 },
      { month: 'Apr 2024', income: 55000 },
      { month: 'May 2024', income: 49000 },
      { month: 'Jun 2024', income: 58000 }
    ];
    
    return {
      dailyHours,
      dailyIncome,
      monthlyIncome,
      workCapacity
    };
  };

  const renderDashboardPage = () => {
    return (
      <div className="dashboard-page">
        <div className="page-header">
          <h1>Welcome, {user?.name}! 👋</h1>
          {notifications.length > 0 && (
            <div className="notifications-panel">
              <div className="notification-badge">
                📢 {notifications.length} New Offer{notifications.length !== 1 ? 's' : ''}
              </div>
              <div className="notifications-list">
                {notifications.map(notification => (
                  <div key={notification.id} className="notification-item">
                    <div className="notification-content">
                      <h4>{notification.title}</h4>
                      <p>{notification.message}</p>
                      <small>{new Date(notification.timestamp).toLocaleString()}</small>
                    </div>
                    <button 
                      className="notification-action"
                      onClick={() => {
                        // Store conversation data in state for the modal
                        const otherParticipant = notification.conversation.participants.find(p => p._id !== user.id);
                        
                        sessionStorage.setItem('pendingChat', JSON.stringify({
                          conversationId: notification.conversationId,
                          receiver: otherParticipant
                        }));
                        
                        // Open chat modal
                        window.dispatchEvent(new CustomEvent('openChatModal'));
                      }}
                    >
                      View Details
                    </button>
                  </div>
                ))}
              </div>
            </div>
          )}
        </div>

        <div className="stats-section">
          <div className="stat-card">
            <div className="stat-icon">💵</div>
            <div className="stat-content">
              <h4>Total Earnings</h4>
              <p className="stat-value">₹{earnings?.total || 0}</p>
            </div>
          </div>
          <div className="stat-card">
            <div className="stat-icon">🎯</div>
            <div className="stat-content">
              <h4>Jobs Completed</h4>
              <p className="stat-value">{earnings?.completedJobs || 0}</p>
            </div>
          </div>
          <div className="stat-card">
            <div className="stat-icon">⏳</div>
            <div className="stat-content">
              <h4>Pending Payments</h4>
              <p className="stat-value">₹{earnings?.pendingPayments || 0}</p>
            </div>
          </div>
        </div>

        <div className="tabs-section">
          <div className="tab-buttons">
            <button 
              className={`tab-btn ${activeTab === 'active' ? 'active' : ''}`}
              onClick={() => setActiveTab('active')}
            >
              🏢 Active Jobs ({myJobs.length})
            </button>
            <button 
              className={`tab-btn ${activeTab === 'available' ? 'active' : ''}`}
              onClick={() => setActiveTab('available')}
            >
              🔍 Available Jobs ({jobs.length})
            </button>
          </div>
        </div>

        {activeTab === 'active' ? (
          <div className="tab-section">
            <div className="section-header">
              <h2>Your Active Jobs</h2>
              <p className="section-subtitle">{myJobs.length} job{myJobs.length !== 1 ? 's' : ''} in progress</p>
            </div>
            {myJobs.length > 0 ? (
              <div className="jobs-list">
                {myJobs.map(job => (
                  <div key={job._id} className="job-card active-job">
                    <div className="job-badge">ACTIVE</div>
                    <div className="job-info">
                      <h3>{job.title}</h3>
                      <p className="job-category">{job.category}</p>
                      <p className="job-employer">👤 {job.employer?.name}</p>
                      <p className="job-location">📍 {job.location?.city}, {job.location?.district}</p>
                      <div className="job-meta">
                        <span>⏱️ Duration: {job.duration?.estimated} {job.duration?.unit}</span>
                      </div>
                    </div>
                    <div className="job-action">
                      <p className="job-price">₹{job.wageCalculation?.totalEstimated}</p>
                      <Link to={`/job/${job._id}`} className="view-btn">View Details</Link>
                    </div>
                  </div>
                ))}
              </div>
            ) : (
              <div className="empty-state">
                <p>No active jobs right now</p>
              </div>
            )}
          </div>
        ) : (
          <div className="tab-section">
            <div className="filter-section">
              <h3><span>🔍</span> Filter by Category</h3>
              <div className="filter-scroll">
                {categories.map(cat => (
                  <button 
                    key={cat.id} 
                    className={`filter-btn ${filter === cat.id ? 'active' : ''}`}
                    onClick={() => setFilter(cat.id)}
                  >
                    <span className="filter-icon">{cat.icon}</span>
                    <span className="filter-label">{cat.label}</span>
                  </button>
                ))}
              </div>
            </div>

            <div className="section-header">
              <h2>Available Jobs for You</h2>
              <p className="section-subtitle">{jobs.length} job{jobs.length !== 1 ? 's' : ''} found</p>
            </div>
            
            {jobs.length > 0 ? (
              <div className="jobs-list">
                {jobs.map(job => (
                  <div key={job._id} className="job-card available-job">
                    <div className="job-header">
                      <h3>{job.title}</h3>
                      <span className={`urgency-badge ${job.urgency}`}>🔴 {job.urgency.toUpperCase()}</span>
                    </div>
                    <p className="job-category">Category: {job.category}</p>
                    <p className="job-employer">👤 Posted by: {job.employer?.name}</p>
                    <p className="job-location">📍 {job.location?.city}, {job.location?.address}</p>
                    <div className="job-details">
                      <div className="detail-item">
                        <span className="label">⏱️ Duration:</span>
                        <span className="value">{job.duration?.estimated} {job.duration?.unit}</span>
                      </div>
                      <div className="detail-item">
                        <span className="label">💰 Estimated Pay:</span>
                        <span className="value price">₹{job.wageCalculation?.totalEstimated}</span>
                      </div>
                    </div>
                    <p className="job-description">{job.description?.substring(0, 100)}...</p>
                    <div className="job-action-buttons">
                      {job.status === 'assigned' && job.assignedWorkers && job.assignedWorkers.some(aw => aw.worker.toString() === user.id) ? (
                        <button 
                          className="apply-btn accept-job-btn"
                          onClick={() => handleAcceptJob(job._id)}
                        >
                          ✅ Accept Job
                        </button>
                      ) : (
                        <button 
                          className="apply-btn"
                          onClick={() => handleApplyJob(job._id)}
                          disabled={appliedJobs.has(job._id) || applyingJobId === job._id}
                        >
                          {appliedJobs.has(job._id) ? '✅ Applied' : (applyingJobId === job._id ? '⏳ Applying...' : '📝 Apply Now')}
                        </button>
                      )}
                      <Link to={`/job/${job._id}`} className="view-btn-large">View Details</Link>
                    </div>
                  </div>
                ))}
              </div>
            ) : (
              <div className="empty-state">
                <p>No jobs found matching your skills right now.</p>
                <p className="empty-hint">Check back later or explore other categories!</p>
              </div>
            )}
          </div>
        )}
      </div>
    );
  };

  const renderHistoryPage = () => {
    // Calculate averages
    const avgDailyHours = workAnalytics.summary?.averageDailyHours || 
      (workAnalytics.dailyHours.length > 0 
        ? (workAnalytics.dailyHours.reduce((sum, item) => sum + item.hours, 0) / workAnalytics.dailyHours.length).toFixed(1)
        : 0);
    
    const avgDailyIncome = workAnalytics.summary?.averageDailyIncome ||
      (workAnalytics.dailyIncome.length > 0
        ? (workAnalytics.dailyIncome.reduce((sum, item) => sum + item.income, 0) / workAnalytics.dailyIncome.length).toFixed(0)
        : 0);
    
    const totalMonthlyIncome = workAnalytics.monthlyIncome.length > 0
      ? workAnalytics.monthlyIncome[workAnalytics.monthlyIncome.length - 1]?.income || 0
      : 0;
    
    const avgCapacity = workAnalytics.summary?.averageCapacity ||
      (workAnalytics.workCapacity.length > 0
        ? (workAnalytics.workCapacity.reduce((sum, item) => sum + item.capacity, 0) / workAnalytics.workCapacity.length).toFixed(0)
        : 0);
    
    return (
      <div className="history-page">
        <div className="page-header">
          <h1>📊 Work Analytics & History</h1>
          <div className="analytics-filters">
            <select 
              value={analyticsFilter}
              onChange={(e) => {
                setAnalyticsFilter(e.target.value);
                fetchWorkAnalytics();
              }}
              className="filter-select"
            >
              <option value="7days">Last 7 Days</option>
              <option value="30days">Last 30 Days</option>
              <option value="90days">Last 90 Days</option>
            </select>
          </div>
        </div>

        {/* Summary Cards */}
        <div className="analytics-summary">
          <div className="analytic-card">
            <div className="card-icon">⏱️</div>
            <div className="card-content">
              <h3>Avg Hours/Day</h3>
              <p className="card-value">{avgDailyHours} hrs</p>
              <p className="card-desc">Average working hours</p>
            </div>
          </div>
          
          <div className="analytic-card">
            <div className="card-icon">💰</div>
            <div className="card-content">
              <h3>Daily Income</h3>
              <p className="card-value">₹{avgDailyIncome}</p>
              <p className="card-desc">Average per day</p>
            </div>
          </div>
          
          <div className="analytic-card">
            <div className="card-icon">📅</div>
            <div className="card-content">
              <h3>Monthly Income</h3>
              <p className="card-value">₹{totalMonthlyIncome.toLocaleString()}</p>
              <p className="card-desc">Latest month</p>
            </div>
          </div>
          
          <div className="analytic-card">
            <div className="card-icon">💪</div>
            <div className="card-content">
              <h3>Work Capacity</h3>
              <p className="card-value">{avgCapacity}%</p>
              <p className="card-desc">Average capacity</p>
            </div>
          </div>
        </div>

        {/* Charts Section */}
        <div className="charts-section">
          <div className="chart-container">
            <h3>📈 Daily Working Hours</h3>
            <div className="bar-chart">
              {workAnalytics.dailyHours.map((item, index) => (
                <div key={index} className="chart-bar">
                  <div 
                    className="bar-fill" 
                    style={{ height: `${(item.hours / 14) * 100}%` }}
                  >
                    <span className="bar-value">{item.hours}h</span>
                  </div>
                  <span className="bar-label">{item.date}</span>
                </div>
              ))}
            </div>
          </div>

          <div className="chart-container">
            <h3>💰 Daily Income Trend</h3>
            <div className="line-chart">
              <div className="chart-grid">
                {[0, 25, 50, 75, 100].map(level => (
                  <div key={level} className="grid-line" style={{ bottom: `${level}%` }}></div>
                ))}
              </div>
              <div className="chart-line">
                {workAnalytics.dailyIncome.map((item, index) => {
                  const maxIncome = Math.max(...workAnalytics.dailyIncome.map(d => d.income));
                  const heightPercent = maxIncome > 0 ? (item.income / maxIncome) * 80 : 0;
                  return (
                    <div 
                      key={index} 
                      className="line-point"
                      style={{ 
                        left: `${(index / (workAnalytics.dailyIncome.length - 1)) * 100}%`,
                        bottom: `${heightPercent}%`
                      }}
                    >
                      <div className="point-tooltip">₹{item.income}</div>
                    </div>
                  );
                })}
              </div>
              <div className="chart-x-axis">
                {workAnalytics.dailyIncome.map((item, index) => (
                  <span key={index} className="x-label">{item.date}</span>
                ))}
              </div>
            </div>
          </div>

          <div className="chart-container">
            <h3>📊 Monthly Income Overview</h3>
            <div className="column-chart">
              {workAnalytics.monthlyIncome.map((item, index) => (
                <div key={index} className="column-item">
                  <div 
                    className="column-bar" 
                    style={{ height: `${(item.income / 60000) * 100}%` }}
                  >
                    <span className="column-value">₹{item.income.toLocaleString()}</span>
                  </div>
                  <span className="column-label">{item.month}</span>
                </div>
              ))}
            </div>
          </div>

          <div className="chart-container">
            <h3>💪 Work Capacity Utilization</h3>
            <div className="capacity-chart">
              {workAnalytics.workCapacity.map((item, index) => (
                <div key={index} className="capacity-item">
                  <div className="capacity-circle">
                    <svg viewBox="0 0 36 36" className="circular-chart">
                      <path className="circle-bg"
                        d="M18 2.0845
                          a 15.9155 15.9155 0 0 1 0 31.831
                          a 15.9155 15.9155 0 0 1 0 -31.831"
                      />
                      <path className="circle"
                        strokeDasharray={`${item.capacity}, 100`}
                        d="M18 2.0845
                          a 15.9155 15.9155 0 0 1 0 31.831
                          a 15.9155 15.9155 0 0 1 0 -31.831"
                      />
                    </svg>
                    <div className="capacity-text">
                      <span className="capacity-percent">{item.capacity}%</span>
                    </div>
                  </div>
                  <span className="capacity-date">{item.date}</span>
                </div>
              ))}
            </div>
          </div>
        </div>

        {/* Earnings Summary */}
        <div className="earnings-summary">
          <div className="earn-card">
            <h3>💰 Total Earnings</h3>
            <p className="earn-value">₹{earnings?.total || 0}</p>
          </div>
          <div className="earn-card">
            <h3>✅ Jobs Completed</h3>
            <p className="earn-value">{earnings?.completedJobs || 0}</p>
          </div>
          <div className="earn-card">
            <h3>⏳ Pending Payments</h3>
            <p className="earn-value">₹{earnings?.pendingPayments || 0}</p>
          </div>
        </div>

        <div className="monthly-breakdown">
          <h3>📅 Monthly Earnings Breakdown</h3>
          <div className="earnings-table">
            {Object.keys(monthlyEarnings).length > 0 ? (
              <table>
                <thead>
                  <tr>
                    <th>Month</th>
                    <th>Earnings</th>
                  </tr>
                </thead>
                <tbody>
                  {Object.entries(monthlyEarnings).map(([month, amount]) => (
                    <tr key={month}>
                      <td>{month}</td>
                      <td className="amount">₹{amount}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            ) : (
              <p className="no-data">No earnings history yet</p>
            )}
          </div>
        </div>
      </div>
    );
  };

  const renderSettingsPage = () => {
